import React from 'react'
import { Route, Routes } from 'react-router-dom'

function CombinedRoutes({routes}) {
  return (
    <React.Fragment>
        <Routes>
            {routes.map((route) => (
                <Route key={route.id} path={route.path} element={route.component} />
            ))}
        </Routes>
    </React.Fragment>
  )
}

export default CombinedRoutes